"""
MKT Original Commentary — Judges chapters 18–19
Run: python3 scripts/zc-original-judges-18-19.py

Chapters covered:
- Ch18: Danite migration — scouts, Micah's shrine plundered, Laish conquered,
  idolatrous Dan cult established ("as long as the house of God was at Shiloh")
- Ch19: The Levite's concubine — Gibeah's crime, the concubine's death,
  the 12-piece dismemberment summons

Key philological foci:
- Ch18: nāḥălāh (inheritance — Dan has none); melek (no king again);
  gôrāl (lot); yāšaḇ lāḇeṭaḥ (dwelling securely — Laish's vulnerability);
  ḥērem (devoted destruction — they struck Laish); pesel (graven image);
  Jonathan son of Gershom son of Moses — the priestly lineage of idolatry
- Ch19: pîlegeš (concubine — secondary wife with no inheritance rights);
  zānāh (played the harlot — wife's infidelity or desertion);
  ṭôḇ-lēḇ (merry/good heart — festive hospitality that delays departure);
  ʾanšê bəliyyaʿal (sons of Belial — worthless/destructive men);
  yāḏaʿ (know — sexual euphemism used in Gen 19 Sodom parallel);
  ʿinnāh (afflict/violate); nəḇālāh (disgrace/outrage — the verdict word);
  wayyaḥăzēq (he seized her); patah/nātaḥ (pieces — the 12 dismemberment)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "18": {
    "1": "<p><em>bayyāmîm hāhēm ʾên meleḵ bəyiśrāʾēl ûḇayyāmîm hāhēm šēḇeṭ haddānî məḇaqquēš-lô nāḥălāh lāšeḇet kî lōʾ-nāpəlāh lô ʿaḏ hayyôm hahûʾ bəṯôk šibṭê yiśrāʾēl bənāḥălāh</em> — 'In those days there was no king in Israel, and in those days the tribe of Dan was seeking for itself an inheritance (<em>nāḥălāh</em>) to live in, for to that day no inheritance had fallen to them among the tribes of Israel.' The chapter opens with the double refrain (<em>ʾên meleḵ bəyiśrāʾēl</em>) and immediately maps its consequence: without covenant order, even territorial inheritance breaks down. <em>nāḥălāh</em> (H5159, inheritance — the covenantal land-gift, what YHWH promised and Joshua distributed) — Dan's failure to secure their allotment (Josh 19:40-48; cf. Judg 1:34 — the Amorites pushed them back) means they exist as a landless tribe, contrary to covenant purpose. Their solution (migration north) is presented without divine sanction.</p>",
    "2": "<p><em>wayyišləḥû bənê-ḏān mimmišpaḥtām ḥămiššāh ʾănāšîm miqṣôtām ʾanšê bənê-ḥayil</em> — 'The sons of Dan sent from their clan five men from their extremities, men of valor.' <em>miqqəṣôtām</em> (from their extremities/fringes — the whole tribe represented by men from the outer edges) — the extremity language suggests comprehensive representation. <em>ʾanšê bənê-ḥayil</em> (H2428 H1121, men of valor/capability) — the same phrase used of Boaz (Ruth 2:1) and Gideon's greeting (Judg 6:12). The reconnaissance mission echoes the Exodus-era spies (Num 13), but without Moses's authorization or YHWH's command — a structural parallel that underscores the absence of divine guidance.</p>",
    "6": "<p><em>wayyōʾmer lāhem hakkōhēn ləkû ləšālôm nekōaḥ YHWH darkəkem ʾăšer tēlkû-ḇāh</em> — 'The priest said to them: Go in peace. The way in which you go is before YHWH.' The Levite-priest pronounces an oracle of favorable outcome — but the text provides no indication that he actually inquired of YHWH, nor is the <em>ʾêpôḏ</em> or <em>tərāpîm</em> (v5 — 'they inquired of God' via Micah's unauthorized shrine) a legitimate instrument of divine revelation. <em>nekōaḥ YHWH</em> (before/in the sight of YHWH) is the priestly blessing formula used to validate the journey — but the entire apparatus (private shrine, private Levite, idols) is corrupt. The oracle may be technically fulfilled, yet its source is polluted.</p>",
    "7": "<p><em>wayyēlkû ḥămiššāh hāʾănāšîm wayyāḇōʾû lāyišāh wayyirʾû ʾet-hāʿām ʾăšer-bəqirḇāh yōšeḇet lāḇeṭaḥ</em> — 'The five men went and came to Laish and saw the people who were in it, dwelling in security (<em>yōšeḇet lāḇeṭaḥ</em>).' <em>lāḇeṭaḥ</em> (H983, in security/trust — the state of dwelling without fear of attack) — this word is used of Israel dwelling securely under YHWH's protection (Deut 33:12,28; Judg 8:11). The people of Laish are described with four vulnerability markers: dwelling securely, manner of Sidon (peaceful/commercial not military), quiet and unsuspecting (<em>šōqēṭ wəḇōṭēaḥ</em>), no lack of anything, far from Sidon and from anyone who might rescue them (<em>miyyad mêṣar</em> — no deliverer). This accumulation of vulnerability terms prepares the reader to be troubled, not cheered, by what follows.</p>",
    "14": "<p><em>wayaʿănû ḥămiššāh hāʾănāšîm hahōlkîm lərāggēl ʾet-ʾereṣ lāyiš wayyōʾmərû ʾel-ʾăḥêhem</em> — 'Then the five men who went to spy out the land of Laish answered and said to their brothers.' The men know Micah's house contains a <em>pesel ûmassēkāh ʾêpôḏ ûtərāpîm</em> (graven image, molten image, ephod, and teraphim) and direct the tribe to take them. The casual recommendation to steal a shrine's sacred objects — instruments of covenant violation — is presented as pragmatic military intelligence, not sacrilege. That 600 armed men will stop to plunder a private household's religious objects on their way to conquer a city reveals the total inversion of values that marks the book's closing chapters.</p>",
    "19": "<p><em>wayyōʾmərû lô ḥăraš śîm-yāḏəkā ʿal-pîkā ûlēk ʿimmānû wihyēh-lānû ləʾāḇ ûləkōhēn</em> — 'They said to him: Be silent; put your hand on your mouth, and come with us and be to us a father and a priest.' <em>ḥărēš</em> (H2790, be silent) — the command to silence is coercive: be quiet about this theft. <em>ləʾāḇ ûləkōhēn</em> (father and priest) — the Levite will gain a tribe-level priestly role rather than a household one. His ready acceptance (<em>wayyîṭaḇ lēḇ hakkōhēn</em> — the priest's heart was glad, v20) reveals his mercenary character: priesthood is portable and negotiable, not a covenant vocation. The offer parodies legitimate Levitical ministry: Aaron was 'mouth and priest' to Moses; this Levite becomes 'priest' to stolen idols.</p>",
    "27": "<p><em>wəhēmmāh lāqəḥû ʾēt ʾăšer-ʿāśāh mîkāh wəʾet-hakkōhēn ʾăšer hāyāh-lô wayyāḇōʾû ʿal-lāyiš ʿal-ʿam šōqēṭ ûḇōṭēaḥ wayyakkû ʾôtām ləpî-ḥāreḇ</em> — 'They took what Micah had made, and the priest who had been his, and came to Laish, to a people quiet and unsuspecting, and struck them with the edge of the sword.' <em>ḥāreḇ</em> (H2719, sword) — the conquest of Laish with the sword echoes the Canaanite conquests of Joshua, but without YHWH's command, without legitimate territory, against a peaceful people. <em>ʾên maṣṣîl</em> (H5337, no one delivering/rescuing) — Laish had no deliverer, as the spies noted (v28). The sad irony: Israel, who was delivered from Egypt by YHWH when no human could save them, now acts as the unchecked oppressor of an undefended people.</p>",
    "30": "<p><em>wayyāqîmû lāhem bənê-ḏān ʾet-happāsel wayyōnāṯān ben-gərōšōm ben-mōšeh hûʾ ûḇānāyw hāyû kōhănîm laššēḇeṭ haddānî</em> — 'The sons of Dan set up the carved image for themselves, and Jonathan son of Gershom, son of Moses, he and his sons were priests to the tribe of Dan.' The genealogical bombshell: the anonymous 'Levite' of chs17-18 is revealed as Jonathan son of Gershom son of Moses — Moses's own grandson is the first idolatrous priest of Danite Israel. Some manuscripts read <em>mənašše</em> (Manasseh) with a superscripted <em>nun</em> — a scribal protective alteration to spare Moses the shame. But the earliest tradition (and the Qere) reads <em>mōšeh</em>: Moses's grandson. The priestly dynasty of Micah's idolatrous shrine serves Dan <em>ʿaḏ yôm gəlôt hāʾāreṣ</em> — until the day of the land's exile (Assyrian conquest, 722 BCE).</p>",
    "31": "<p><em>wayyāśîmû lāhem ʾet-pesel mîkāh ʾăšer ʿāśāh kol-yəmê heyôt bêt-hāʾĕlōhîm bəšilōh</em> — 'They set up Micah's carved image that he made, all the days that the house of God was at Shiloh.' The conclusion is devastating: while the legitimate tabernacle stood at Shiloh (<em>bêt-hāʾĕlōhîm bəšilōh</em>), Dan maintained its idolatrous shrine in the north. Two cult sites, one legitimate and authorized, one stolen and unauthorized — the parallel existence of covenant and apostasy across the tribal period. Shiloh's eventual destruction (1 Sam 4; Jer 7:12-14) does not close the northern shrine; the Danite idolatry outlasts the legitimate sanctuary, a testimony to how deeply apostasy takes root.</p>"
  },
  "19": {
    "1": "<p><em>wayhî bayyāmîm hāhēm ûmeleḵ ʾên bəyiśrāʾēl wayhî ʾîš lēwî gār bəyarktê har-ʾeprayim wayyiqqaḥ-lô ʾiššāh pîlegeš mibêt leḥem yəhûḏāh</em> — 'It came to pass in those days when there was no king in Israel that a certain Levite was sojourning (<em>gār</em>) in the remote parts of the hill country of Ephraim, and he took a concubine (<em>pîlegeš</em>) from Bethlehem in Judah.' The no-king formula sets the moral context. <em>pîlegeš</em> (H6370, concubine — a secondary wife with sexual rights but no inheritance claims; the word may be related to Akkadian <em>pilakku</em>, spindle-woman) — her status is ambiguous legally: she has the intimacy of a wife without full covenant protection. <em>gār</em> (H1481, to sojourn — to live in a place without full citizenship) — the Levite is himself a sojourner, dependent on hospitality, without territorial roots; his social vulnerability mirrors hers.</p>",
    "2": "<p><em>wattizneh ʿālāyw pîlagšô wattellex mēʾittô ʾel-bêt ʾāḇîhā ʾel-bêt leḥem yəhûḏāh</em> — 'His concubine played the harlot against him (<em>wattizneh</em>) and went from him to her father's house in Bethlehem in Judah.' <em>zānāh</em> (H2181, to play the harlot/be unfaithful) — the verb can mean literal prostitution, infidelity in marriage, or in a softer reading simply 'became angry with him and left.' The LXX reads 'she was angry with him' — some scholars prefer this softer sense given his later tender retrieval of her (v3: 'to speak to her heart,' a covenant love idiom). The four-month separation (<em>yāmîm ʾarbaʿāh ḥodāšîm</em>) implies an extended estrangement, not a one-night departure.</p>",
    "3": "<p><em>wayyāqom ʾîšāh wayyelek ʾaḥărêhā lədabbēr ʿal-libbāh</em> — 'Her husband arose and went after her to speak to her heart.' <em>ḏibbēr ʿal-lēḇ</em> (H1696 H3820, to speak to/upon the heart) is the OT idiom for words of tender comfort and persuasion — used of Isaac comforting Rebekah (Gen 24:67, LXX), of Shechem wooing Dinah (Gen 34:3), of Boaz's kindness to Ruth (Ruth 2:13). The Levite goes to win back his alienated wife with words of covenant love. He brings a servant and two donkeys (<em>ḥămôr</em>) — the travel equipment of a man serious about the journey. The father-in-law's repeated hospitality that delays their departure sets up the tragedy that follows.</p>",
    "14": "<p><em>wayyaʿaḇrû wayyēlkû ûtāḇōʾ lāhem haššemeš ʾeṣel haggibəʿāh ʾăšer ləḇinyāmîn</em> — 'They passed on and went, and the sun set on them near Gibeah, which belongs to Benjamin.' The geographical detail is crucial: they chose Gibeah of Benjamin (<em>giḇʿāh ʾăšer ləḇinyāmîn</em>) over Jebus (Jerusalem, still a non-Israelite city). The servant had suggested Jebus; the Levite refused to enter a foreign city, choosing Gibeah — Israelite, Benjaminite, presumably safe (v12 — 'we will not turn aside into a city of foreigners who are not of the sons of Israel'). The choice of the 'safer' Israelite city leads to the worse outcome: the horror at Gibeah will surpass anything a Canaanite city could have done.</p>",
    "15": "<p><em>wayyāsurrû šām lāḇôʾ lālûn bəgiḇʿāh wayyāḇōʾ wayyēšeḇ birḥôḇ hāʿîr wəʾên ʾîš mēʾasēp ʾôtām habbayətāh lālûn</em> — 'They turned aside there to go in to spend the night at Gibeah. He went in and sat in the town square, but there was no one who took them into his house to spend the night.' <em>rəḥôḇ</em> (H7339, the open square/broad place at a city gate) — sitting in the city square was the standard way to signal that you needed hospitality. <em>wəʾên ʾîš mēʾasēp</em> (no man gathering them in) — the failure of hospitality is the first sign of Gibeah's moral collapse. In the ancient Near East, hospitality to travelers was a near-absolute obligation; its absence signals a community that has ceased to function by covenant norms.</p>",
    "20": "<p><em>wayyōʾmer hazzāqēn šālôm lāk raq kol-maḥsôrkā ʿālay raq bāreḥôḇ ʾal-tālan</em> — 'The old man said: Peace be to you; I will take care of all your needs; only do not spend the night in the square.' The old man's warning — 'do not spend the night in the square' — reveals that he knows the danger. He is a sojourner too (<em>gēr</em> v16 — from Ephraim, not a native Benjaminite), which may be why he, unlike the locals, shows hospitality: he knows what it is to need it. His injunction encodes the same vulnerability assessment the spies gave about Laish (18:7 — dwelling secure, no deliverer nearby) but in an Israelite city.</p>",
    "22": "<p><em>hēmmāh mêṭîḇîm ʾet-libbām wəhinnēh ʾanšê hāʿîr ʾanšê bənê-ḇəliyyaʿal nāsabû ʾet-habbayit mitdappəqîm ʿal-haddālet</em> — 'While they were making their hearts merry, the men of the city, men who were sons of Belial (<em>bənê bəliyyaʿal</em>), surrounded the house, beating on the door.' <em>bənê bəliyyaʿal</em> (H1121 H1100, sons of worthlessness/destruction — the term for those who have broken all moral constraints) is the same phrase used in Deut 13:13 for those who lead a city into idolatry and in 1 Sam 2:12 for Eli's sons. <em>nāsab</em> (H5437, to surround/encircle) + <em>mitdappəqîm ʿal-haddālet</em> (beating on the door) — the scene directly parallels Gen 19:4-9 where Sodom's men surrounded Lot's house. The echo is intentional: Gibeah of Benjamin has become Sodom. An Israelite city in the Promised Land reproduces the worst act of Canaan's condemned cities.</p>",
    "24": "<p><em>hinnēh bittî habbəṯûlāh wəpilagšēhû ʾôṣîʾāh nāʾ ʾôtām wəʿannû ʾôtām waaʿăśû lāhem haṭṭôḇ bəʿênêkem</em> — 'Behold, here are my virgin daughter and his concubine. Let me bring them out. Violate them and do with them what is good in your eyes.' The host offers his daughter and the concubine to protect the male guest — an act that reflects the extreme ancient Near Eastern hospitality code (protecting the guest at all costs) but violates the equally fundamental code of protection of women. <em>ʿinnāh</em> (H6031, to afflict/violate/humble — used for sexual violation in Gen 34:2 Dinah; 2 Sam 13:12 Tamar) — the offer to 'violate' them with this word makes the proposed act explicit. <em>haṭṭôḇ bəʿênêkem</em> (what is good in your eyes) — echoes Judges' refrain: the crowd will do what is right in their own eyes, the ultimate collapse of covenant standards.</p>",
    "25": "<p><em>wəlōʾ ʾāḇû hāʾănāšîm lišmōaʿ lô wayyaḥăzēq hāʾîš bəpilagšô wayyōṣēʾ ʾălêhem haxûṣāh wayyēḏəʿû ʾôtāh wayyitʿallălû-ḇāh kol-hallaylāh ʿaḏ-habbōqer</em> — 'But the men would not listen to him. So the man seized his concubine and thrust her out to them outside, and they knew her and abused her all night until the morning.' <em>wayyaḥăzēq</em> (H2388, he seized/grabbed — the verb of force) — the Levite's action is brutal: he seizes (<em>ḥāzaq</em>) his concubine, the one he came to retrieve with tender words, and thrusts her to the mob. <em>wayyēḏəʿû ʾôtāh</em> (H3045, they knew her — the same sexual euphemism as Gen 4:1 and Gen 19:5) — gang rape continuing all night. <em>wayyitʿallălû-ḇāh</em> (H5953, they abused/treated wickedly — from <em>ʿālal</em>, to act severely against) — the compound horror: the night-long assault destroys her.</p>",
    "28": "<p><em>wayyōʾmer ʾēlêhā qûmî wənēlēkāh wəʾên ʿōneh wayyiqqāḥêhā ʿal-haḥămôr wayyāqom hāʾîš wayyelek limqōmô</em> — 'He said to her: Arise, let us be going. But there was no answer.' The brutal simplicity of the Levite's response to finding her at the threshold: 'Get up, let's go.' No grief expressed, no lamentation — then the most chilling detail in the chapter: <em>wəʾên ʿōneh</em> (there was no answer). She is dead at the threshold, her hands on the doorway (v27 — as if still reaching for protection she never received). His matter-of-fact loading of the body onto the donkey and journeying home is presented without comment — the narrator trusts the reader to feel the horror he does not narrate.</p>",
    "29": "<p><em>wayyāḇōʾ ʾel-bêtô wayyiqqaḥ ʾet-hammaʾăkelet wayyaḥăzēq bəpilagšô waynattəḥêhā laʿăṣāmêhā lišnêm ʿāśār nətāḥîm wayyəšallāḥêhā bəkol gəḇûl yiśrāʾēl</em> — 'When he entered his house, he took a knife, seized his concubine, and cut her into twelve pieces, limb by limb, and sent her throughout all the territory of Israel.' <em>maʾăkelet</em> (H3979, knife/slaughtering knife — from <em>ʾākal</em> to eat; used for the sacrificial knife Abraham took to Moriah, Gen 22:6,10) — the same instrument of ritual sacrifice becomes an instrument of political summons. <em>nātaḥ</em> (H5408, to cut up/divide in pieces — the word for dismembering a sacrificial animal, Lev 1:6; Exod 29:17) — the cutting is described with the vocabulary of sacrifice. The twelve pieces correspond to the twelve tribes — a territorial summons, sending to every boundary (<em>gəḇûl</em>) of Israel. The act mirrors the cutting of the covenant animal (Gen 15:10,17; Jer 34:18-19) — broken covenant requires a response.</p>",
    "30": "<p><em>wayhî kol-hārōʾeh wəʾāmar lōʾ-nihtəyətāh wəlōʾ nirʾətāh kāzōʾt lemibbennê yiśrāʾēl miyyôm ʿălôt bənê-yiśrāʾēl mēʾereṣ miṣrayim ʿaḏ hayyôm hazzeh śîmû-lākem ʿālêhā ʿūṣû ûḏabbērû</em> — 'Everyone who saw it said: Nothing like this has happened or been seen from the day the sons of Israel came up from the land of Egypt until this day. Set your heart on it, take counsel, and speak.' <em>lōʾ-nihtəyəṯāh wəlōʾ nirʾəṯāh kāzōʾt</em> (nothing like this has been done or seen) — the hyperbole of moral horror: this is the worst thing that has happened since the Exodus, which is the founding event of the nation's existence. The repetition of <em>nihtəyəṯāh / nirʾəṯāh</em> (happened/seen) emphasizes unprecedented evil. The call to 'set your heart on it, take counsel, and speak' (<em>śîmû... ʿūṣû... ḏabbərû</em>) is a summons to corporate covenant response — what Israel does next will determine whether it can still function as YHWH's covenant people.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'judges')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', 'judges', c)
    print(f'judges mkt-original: wrote {sum(len(v) for v in ORIGINAL.values())} verses across ch 18-19')

if __name__ == '__main__':
    main()
